"use strict";(globalThis.webpackChunkeo_glossary=globalThis.webpackChunkeo_glossary||[]).push([[607],{54793(e){e.exports=JSON.parse('{"tag":{"label":"to be discussed","permalink":"/eo-glossary/tags/to-be-discussed","allTagsPath":"/eo-glossary/tags","count":36,"items":[{"id":"terms/calibration","title":"Calibration","description":"Process of quantitatively defining a system\'s (e.g. a Sensor or Model\'s) response to known, controlled inputs produced by references. In Remote Sensing, implies the collection of pre-flight and in-flight calibration measurements and in-situ Data.","permalink":"/eo-glossary/terms/calibration"},{"id":"terms/characteristic","title":"Characteristic","description":"Distinguishing Feature of an object or entity, which can be inherent or assigned, and qualitative or quantitative.","permalink":"/eo-glossary/terms/characteristic"},{"id":"terms/classification_system_levels","title":"Classification System Levels","description":"Levels in a hierarchical Classification System.","permalink":"/eo-glossary/terms/classification_system_levels"},{"id":"terms/copernicus_service_provider","title":"Copernicus Service Provider","description":"Institutional body, organisation or programme that provides reliable, trusted EO Information and has the financial resources to sustain the provision.","permalink":"/eo-glossary/terms/copernicus_service_provider"},{"id":"terms/data_access","title":"Data Access","description":"Service to disseminate Data.","permalink":"/eo-glossary/terms/data_access"},{"id":"terms/earth_observation","title":"Earth Observation","description":"Science domain dealing with technologies and methods of collecting and analyzing observations about the different Earth spheres.","permalink":"/eo-glossary/terms/earth_observation"},{"id":"terms/feature","title":"Feature","description":"Abstraction of real-world phenomena.","permalink":"/eo-glossary/terms/feature"},{"id":"terms/forecast_range","title":"Forecast Range","description":"The forecast period.","permalink":"/eo-glossary/terms/forecast_range"},{"id":"terms/geolocation_information","title":"Geolocation Information","description":"Information used to determine geographic Location.","permalink":"/eo-glossary/terms/geolocation_information"},{"id":"terms/geopositioning","title":"Geopositioning","description":"Determination of the geographic Position of a point (0D) or linear (1D) Feature.","permalink":"/eo-glossary/terms/geopositioning"},{"id":"terms/georectifying","title":"Georectifying","description":"Correcting for positional displacement with respect to the surface of the Earth.","permalink":"/eo-glossary/terms/georectifying"},{"id":"terms/impact","title":"Impact","description":"Regarded long-term according to X. However, in the Horizon Europe Missions terminology, regarded short-term.","permalink":"/eo-glossary/terms/impact"},{"id":"terms/in-situ_observation","title":"In-Situ Observation","description":"Observations performed in the same Place where a Phenomenon occurs, normally without isolating it from other systems or altering its pre-Observation state.","permalink":"/eo-glossary/terms/in-situ_observation"},{"id":"terms/laboratory_observation","title":"Laboratory Observation","description":"Usually in-situ observations in which the Object or Phenomenon is isolated from other systems or altered in its original conditions or environment.","permalink":"/eo-glossary/terms/laboratory_observation"},{"id":"terms/latency","title":"Latency","description":"Period between the end of sensing of a Phenomenon to the beginning of availability of a specific product.","permalink":"/eo-glossary/terms/latency"},{"id":"terms/measurement","title":"Measurement","description":"Observation of a Quantity.","permalink":"/eo-glossary/terms/measurement"},{"id":"terms/measurement_uncertainty","title":"Measurement Uncertainty","description":"Uncertainty associated with the method of Measurement.","permalink":"/eo-glossary/terms/measurement_uncertainty"},{"id":"terms/model","title":"Model","description":"An, often numeric, theoretical (or otherwise abstract) representation of an Entity intended to generate Data describing one or more of its traits.","permalink":"/eo-glossary/terms/model"},{"id":"terms/near_real_time_data","title":"Near Real Time Data","description":"Data available for use with a specified (small and application dependent) latency, typically 3 hours for meteorological applications.","permalink":"/eo-glossary/terms/near_real_time_data"},{"id":"terms/observation","title":"Observation","description":"Act of determining the Value of a Property by interacting in a reproducible way with the Phenomenon using a Sensor.","permalink":"/eo-glossary/terms/observation"},{"id":"terms/policy","title":"Policy","description":"Deliberate system of guidelines to guide decisions and achieve rational outcomes, implemented as a procedure or protocol and typically promulgated through official written documents.","permalink":"/eo-glossary/terms/policy"},{"id":"terms/policy_cycle","title":"Policy Cycle","description":"Well-established concept typically taught as the rational model of policy decision-making, representing an idealised view of the policy process.","permalink":"/eo-glossary/terms/policy_cycle"},{"id":"terms/policy_file","title":"Policy File","description":"Policy documents that represent the official written reference for a given Policy.","permalink":"/eo-glossary/terms/policy_file"},{"id":"terms/policy_making","title":"Policy Making","description":"Process by which governments translate their political vision into programmes and actions to deliver outcomes \u2014 desired change in the real world.","permalink":"/eo-glossary/terms/policy_making"},{"id":"terms/policy_milestone","title":"Policy Milestone","description":"Markers of significant progress in addressing specific issues, or crucial decision points where significant choices are made within a policy process.","permalink":"/eo-glossary/terms/policy_milestone"},{"id":"terms/policy_objective","title":"Policy Objective","description":"Desired outcome that policymakers wish to achieve.","permalink":"/eo-glossary/terms/policy_objective"},{"id":"terms/policy_target","title":"Policy Target","description":"Specific level or rate set for the Policy Objective.","permalink":"/eo-glossary/terms/policy_target"},{"id":"terms/position","title":"Position","description":"Place referenced by a single set of coordinates within a coordinate reference system.","permalink":"/eo-glossary/terms/position"},{"id":"terms/property","title":"Property","description":"Observable Trait.","permalink":"/eo-glossary/terms/property"},{"id":"terms/reference","title":"Reference","description":"Phenomenon whose values for specific properties are known and understood with an Uncertainty significantly lower than that of the Observation with which it is compared.","permalink":"/eo-glossary/terms/reference"},{"id":"terms/remote_sensing","title":"Remote Sensing","description":"Type of Observation performed at a significant distance from a Phenomenon.","permalink":"/eo-glossary/terms/remote_sensing"},{"id":"terms/sample","title":"Sample","description":"Subset of one or more entities.","permalink":"/eo-glossary/terms/sample"},{"id":"terms/spectral_bandwidth","title":"Spectral Bandwidth","description":"Range of the Spectral Band.","permalink":"/eo-glossary/terms/spectral_bandwidth"},{"id":"terms/steward","title":"Steward","description":"Entity responsible for the safe custody, transport, storage of the data and implementation of business rules.","permalink":"/eo-glossary/terms/steward"},{"id":"terms/temporal_revisit","title":"Temporal Revisit","description":"Interval between successive observations.","permalink":"/eo-glossary/terms/temporal_revisit"},{"id":"terms/thematic_uncertainty","title":"Thematic Uncertainty","description":"Uncertainty associated with the method of classification.","permalink":"/eo-glossary/terms/thematic_uncertainty"}],"unlisted":false}}')}}]);